        return UserDefaults(suiteName: userDefaultsSuite)
    }
    
    func saveToUserDefaults(account: String, hashedPassword: String) {
        defaults?.set(hashedPassword, forKey: "hash_\(account)")
        
        var accounts = defaults?.stringArray(forKey: "accounts") ?? []
        if !accounts.contains(account) {
            accounts.append(account)
            defaults?.set(accounts, forKey: "accounts")
        }
        defaults?.synchronize()
    }
    
    func retrieveFromUserDefaults(account: String) -> String? {
        return defaults?.string(forKey: "hash_\(account)")
    }
    
    func deleteFromUserDefaults(account: String) {
        defaults?.removeObject(forKey: "hash_\(account)")
        var accounts = defaults?.stringArray(forKey: "accounts") ?? []
        accounts.removeAll { $0 == account }
        defaults?.set(accounts, forKey: "accounts")
        defaults?.synchronize()
    }
    
    func getAllAccountsFromUserDefaults() -> [String] {
        return defaults?.stringArray(forKey: "accounts") ?? []
    }
