class PasswordManager {
    
    static let shared = PasswordManager()
    
    private let hashingService = PasswordHashingService.shared
    private let storageService = SecureStorageService.shared
    
    private init() {}
    
    // Register a new user with password
    func registerUser(username: String, password: String) -> Result<Void, PasswordError> {
        guard !username.isEmpty else { return .failure(.emptyUsername) }
        guard isPasswordValid(password) else { return .failure(.weakPassword) }
        
        // Check if user already exists
        if storageService.retrieveFromKeychain(account: username) != nil {
            return .failure(.userAlreadyExists)
        }
        
        guard let hashedPassword = hashingService.createStorableHash(from: password) else {
            return .failure(.hashingFailed)
        }
        
        // Save to Keychain (primary) and UserDefaults (backup)
        let keychainSuccess = storageService.saveToKeychain(account: username, hashedPassword: hashedPassword)
        storageService.saveToUserDefaults(account: username, hashedPassword: hashedPassword)
        
        if keychainSuccess {
            return .success(())
        } else {
            return .failure(.storageFailed)
        }
    }
    
    // Authenticate user offline
    func authenticateUser(username: String, password: String) -> Result<Void, PasswordError> {
        guard !username.isEmpty else { return .failure(.emptyUsername) }
        guard !password.isEmpty else { return .failure(.emptyPassword) }
        
        // Try Keychain first, then UserDefaults
        let storedHash: String
        if let keychainHash = storageService.retrieveFromKeychain(account: username) {
            storedHash = keychainHash
        } else if let defaultsHash = storageService.retrieveFromUserDefaults(account: username) {
            storedHash = defaultsHash
        } else {
            return .failure(.userNotFound)
        }
        
        if hashingService.verifyPassword(password, againstStoredHash: storedHash) {
            return .success(())
        } else {
            return .failure(.invalidPassword)
        }
    }
    
    // Change password
    func changePassword(username: String, currentPassword: String, newPassword: String) -> Result<Void, PasswordError> {
        // Verify current password first
        let authResult = authenticateUser(username: username, password: currentPassword)
        switch authResult {
        case .failure(let error):
            return .failure(error)
        case .success:
            break
        }
        
        guard isPasswordValid(newPassword) else { return .failure(.weakPassword) }
        
        guard let newHash = hashingService.createStorableHash(from: newPassword) else {
            return .failure(.hashingFailed)
        }
        
        let keychainSuccess = storageService.saveToKeychain(account: username, hashedPassword: newHash)
        storageService.saveToUserDefaults(account: username, hashedPassword: newHash)
        
        return keychainSuccess ? .success(()) : .failure(.storageFailed)
    }
    
    // Delete user
    func deleteUser(username: String, password: String) -> Result<Void, PasswordError> {
        let authResult = authenticateUser(username: username, password: password)
        switch authResult {
        case .failure(let error):
            return .failure(error)
        case .success:
            break
        }
        
        storageService.deleteFromKeychain(account: username)
        storageService.deleteFromUserDefaults(account: username)
        return .success(())
    }
    
    // Get all registered usernames
    func getAllUsers() -> [String] {
        let keychainAccounts = Set(storageService.getAllAccounts())
        let defaultsAccounts = Set(storageService.getAllAccountsFromUserDefaults())
        return Array(keychainAccounts.union(defaultsAccounts)).sorted()
    }
    
    // Password strength validation
    func isPasswordValid(_ password: String) -> Bool {
        guard password.count >= 8 else { return false }
        
        let hasUppercase = password.range(of: "[A-Z]", options: .regularExpression) != nil
        let hasLowercase = password.range(of: "[a-z]", options: .regularExpression) != nil
        let hasDigit = password.range(of: "[0-9]", options: .regularExpression) != nil
        let hasSpecial = password.range(of: "[^A-Za-z0-9]", options: .regularExpression) != nil
        
        let criteriaMet = [hasUppercase, hasLowercase, hasDigit, hasSpecial].filter { $0 }.count
        return criteriaMet >= 3
    }
    
    func passwordStrength(_ password: String) -> PasswordStrength {
        if password.count < 8 { return .weak }
        
        var score = 0
        if password.count >= 12 { score += 1 }
        if password.count >= 16 { score += 1 }
        if password.range(of: "[A-Z]", options: .regularExpression) != nil { score += 1 }
        if password.range(of: "[a-z]", options: .regularExpression) != nil { score += 1 }
        if password.range(of: "[0-9]", options: .regularExpression) != nil { score += 1 }
        if password.range(of: "[^A-Za-z0-9]", options: .regularExpression) != nil { score += 1 }
        
        switch score {
        case 0...2: return .weak
        case 3...4: return .medium
        default: return .strong
        }
    }
