        case .emptyPassword: return "Password cannot be empty."
        case .weakPassword: return "Password must be at least 8 characters with 3 of: uppercase, lowercase, digit, special character."
        case .userAlreadyExists: return "An account with this username already exists."
        case .userNotFound: return "No account found with this username."
        case .invalidPassword: return "Incorrect password."
        case .hashingFailed: return "Failed to hash password."
        case .storageFailed: return "Failed to save credentials."
        }
    }
}

